(()=>{var prevBtn=document.querySelector(".slider__btn--prev"),nextBtn=document.querySelector(".slider__btn--next"),target=document.querySelector(".slider__items");target.addEventListener("wheel",e=>{e.deltaY>0?target.scrollBy(216,0):target.scrollBy(-216,0)});prevBtn.onclick=e=>target.scrollBy(-216,0);nextBtn.onclick=e=>target.scrollBy(216,0);})();
